import { createStore } from "redux";

const counterReducer = (state = { counter: 0 }, action) => {
    if (action.type === 'increment') {
        return { counter: state.counter + 1 };
    }
    if (action.type === 'decrement') {
        return { counter: state.counter - 1 };
    }

    // How to pass a payload to an action type?
    // Inside the dispatching, just set these arg or payload 
    // in a named arguement passing style, here operator and step bundled through action
    if (action.type === 'stepper') {
        return { counter: eval(`${state.counter} ${action.operator} ${action.step}`) };
    }

    return state;
}

const store = createStore(counterReducer);

export default store;
